sys_script_include.script:
var TaniumIntegrationCore = Class.create();
TaniumIntegrationCore.prototype = {
	// x_taniu_tan_core.TaniumIntegrationCore

	/**
	 * Initialize a TaniumIntegrationCore object from constructor.
	 *
	 * @param {Boolean} [useAPIToken=false] - If true, use the API token instead of the username
	 * @version 2.0.0 - Updated to use API token by default, and to use the API token if the username and password are not set.
	 */
	initialize: function(useAPIToken) {
		useAPIToken = (typeof useAPIToken === 'undefined') ? true : !!useAPIToken;
		var errMsg;
		/*
			Set up environment by retrieving the value of the relevant system properties.
			These values will be validated by the _validateEnvironment() method below.
		*/
		this.SCOPE_PREFIX = 'x_taniu_tan_core';
		this.TANIUM_API_ENDPOINT = gs.getProperty( //constant (but ES5 so no const keyword)
			'x_taniu_tan_core.tanium_api_endpoint',
			''
		);
		this.TANIUM_MODULE_API_ENDPOINT = gs.getProperty(
			'x_taniu_tan_core.tanium_module_api_url',
			''
		);
		this.TANIUM_MID_SERVER = gs.getProperty(
			'x_taniu_tan_core.mid_server',
			''
		);

		//sensitive values - stored in 2-way encrypted properties.
		this.tanium_username = gs.getProperty(
			'x_taniu_tan_core.tanium_username',
			''
		);
		this.tanium_password = gs.getProperty(
			'x_taniu_tan_core.tanium_password',
			''
		);
		this.tanium_api_token = gs.getProperty(
			'x_taniu_tan_core.tanium_api_token',
			''
		);

		/*
		This impacts the behavior of the private ._executeRESTCall() method.
		Only internal code should call that method directly.
		If set to true, the .executeAsync() method of RESTMessageV2 will be used instead of
		 the .execute() method in the ._executeRESTCall() method. This can result in
		 SIGNIFICANTLY  longer time between call and response, but may be preferable if
		 the total number or size of requests/responses is very high, which could otherwise
		 bog down instance performance.
		If the .setRESTAsync() method is not called (or the executeAsync argument is not
		 specified), then the value of this.rest_async will be used to determine whether the
		 request should execute async.
		The default value of that property is false.
		*/
		this.rest_async = false;
		this.test_mode = false;
		this.session_id = '';
		this.question_id = '';
		this.direct_connection_id = '';
		this.endpoint_id = '';
		this.endpoint_serial_number = '';

		//If useAPIToken is false, but username/password are not set and token is,
		// then set useAPIToken to true.
		if (
			!useAPIToken && //useAPIToken is false
			(!this.tanium_username || !this.tanium_password) && //Username or password are not set
			this.tanium_api_token //API token IS set
		) {
			useAPIToken = true;
		}

		/*
			Validate environment.
			If environment not valid, throw error and halt.
		*/
		var environmentState = this._validateEnvironment();
		if (!environmentState.valid) {
			errMsg = 'TaniumIntegrationCore Script Include instantiated, but ' +
				'unable to proceed due to a failed environment validation.';
			if (environmentState.error) {
				errMsg += '\nError: ' + environmentState.error.toString();
			}

			gs.error(errMsg);
			throw new Error(errMsg);
		}

		/*
			If environment is valid, get session ID or API token.
			If useAPIToken is true, use existing API token. If not, hit login API and get
			session ID.
		*/
		if (useAPIToken) {
			this.session_id = this.tanium_api_token;
			if (!this.session_id) {
				errMsg = 'TaniumIntegrationCore Script Include instantiated with useAPIToken argument ' +
					'set to true. However, API token system property is not set. To continue, ' +
					'either set the API token system property or try setting useAPIToken to ' +
					'false. \n' +
					'To get an API token to use in the x_taniu_tan_core.tanium_api_token ' +
					'system property, follow the instructions here: ' +
					'https://docs.tanium.com/platform_user/platform_user/console_api_tokens.html\n' +
					'Generate a new API token and set its expiration to 30+ days. Set the allowed ' +
					'IP addresses to 0.0.0.0/0 to allow ServiceNow to connect from any IP address.';
				gs.error(errMsg);
				throw new Error(errMsg);
			}
		} else { //If useAPIToken is false or not specified, login and get session ID.
			this.session_id = this._loginGetSessionID();
			if (!this.session_id) {
				errMsg = 'TaniumIntegrationCore Script Include instantiated, but unable to proceed due to a ' +
					'login failure. It\'s possible that the credentials stored in the system properties ' +
					'"x_taniu_tan_core.tanium_username" and "x_taniu_tan_core.tanium_password" ' +
					'or the endpoint in the system property "x_taniu_tan_core.tanium_api_endpoint" ' +
					'is invalid.';
				gs.error(errMsg);
				throw new Error(errMsg);
			}
		}

		return this;
	},

	/**
	 * Ask a question of Tanium Interact, using Tanium's natural language engine.
	 * The question ID will be stored as a property of the initialized TaniumIntegrationCore
	 *  object, as well as being returned, so that it can be used to retrieve the question
	 *  response from Tanium using another method (.getQuestionResponse()) .
	 * @param {String} questionText - The "natural language" question text for a Tanium Question.
	 * This should exactly match what would go into the "Question" field in Tanium Interact.
	 * @return {string} - The question ID (which is a number, but is returned as a string).
	 * @example
	 * var questionResponse;
	 * var questionText = 'Get Computer Name and Computer ID and Computer Serial Number and ' +
	 *  'Online?maxAge=300 and AD Domain and Uptime from all machines';
	 * //Initialize an instance of TaniumIntegrationCore, authenticating with the username and
	 *     password provided in the guided setup. var integrationCore = new
	 *     x_taniu_tan_core.TaniumIntegrationCore(false); var questionID =
	 *     integrationCore.askQuestion(questionText); if (!questionID) { throw new Error(
	 *       'Failed to get question ID from Tanium. Possibly malformed question is to blame.\n' +
	 *       'Question text: ' + questionText
	 *    );
	 * }
	 * while (example.responseStillRequired()) {
	 *    questionResponse = integrationCore.getQuestionResponse(questionID);
	 *    example.doSomethingWithLatestResponse(questionResponse);
	 * }
	 * //...
	 */
	askQuestion: function(questionText) {
		var errMsg;
		/*
			Validate environment is clean and ready to go.
		*/
		if (!this.session_id && !this.tanium_api_token) {
			errMsg = 'Unable to ask question. Session ID and API token are both not set in ' +
				'constructor. This should not happen. Please contact your administrator.';
			gs.error(errMsg);
			throw new Error(errMsg);
		}
		if (!questionText) {
			//Question text not provided. Halt and throw.
			errMsg = 'Question text not provided. Unable to ask question without question text ' +
				'being provided. Please pass a string parameter into the .askQuestion() method ' +
				'in order to ask a Tanium question.';
			gs.error(errMsg);
			throw new Error(errMsg);
		}

		this.question_id = this._sendQuestion(questionText);
		gs.debug('Question ID: ' + this.question_id);

		return this.question_id;
	},

	/**
	 * Retrieve the answer to a previously-asked Tanium question.
	 * NOTE: It's important to be aware that if you call this method IMMEDIATELY after calling the
	 *  askQuestion() method, you will get a response, but it will NOT BE COMPLETE. Getting the
	 *  question response will retrieve the CURRENT state of the response. Tanium clients take time
	 *  to respond, so if this method is called immediately after asking the question, no clients
	 *  will have yet had a chance to respond. If you call it again a moment later, perhaps a few
	 *  clients will have responded. A common use-case is to continually call this method every few
	 *  seconds until all clients have responded, and use the updating whatever interface displays
	 *  the response data as the response object is updated, until 100% of clients have responded
	 *  (with no clients responding "current result unavailable"), at which point the question
	 *  response will not change any further, so there's no need to continue calling the API.
	 * @param {string} [questionID=this.question_id] - The ID of the question from Tanium to get
	 *  the answer for (obtained by calling the askQuestion method of this class). If the
	 *  questionID argument is provided when this method is called, the provided question ID
	 *  will be checked for an answer. If not specified, the class-scope property
	 *  this.question_id will be used. This property is automatically set when the askQuestion()
	 *  method is called. This means that if you're using the same instantiation of this class
	 *  from which the question was asked, to retrieve the answer, you don't need to specify the
	 *  questionID argument (unless you're asking multiple questions); but it won't hurt
	 *  anything if you do.
	 * @returns {{}} - The exact JSON object that the server responded with, including nodes like
	 *  "no_results_count"
	 *  @example
	 *  var endpointSerial = 'some_serial_number';
	 * var coreUtil = new x_taniu_tan_core.TaniumIntegrationCore();
	 * var endpointID = coreUtil.getEndpointIDBySerial(endpointSerial);
	 *
	 * if (!endpointID) {
	 *    throw new Error(
	 *       'Unable to retrieve Endpoint ID from Tanium for endpoint with serial ' + endpointSerial
	 *    );
	 * }
	 *
	 * if (coreUtil.establishDirectConnection(endpointID)) {
	 *    example.setDirectConnectionResponse(
	 *       coreUtil.queryOpenDirectConnection()
	 *    );
	 * }
	 */
	getQuestionResponse: function(questionID) {
		var responseBody;
		questionID = (typeof questionID == 'undefined') ? this.question_id : questionID;
		if (!questionID) {
			gs.error(
				'.getQuestionResponse() called without a valid question ID, or previously ' +
				'asked question failed. Unable to retrieve question answer.'
			);
			return false;
		}

		var rQuestionResponse = this._getRESTObject('Tanium Integration Core', 'Get Answer');

		rQuestionResponse.setStringParameterNoEscape(
			'tanium_api_endpoint',
			this.TANIUM_API_ENDPOINT
		);
		rQuestionResponse.setStringParameterNoEscape(
			'question_id',
			questionID
		);

		responseBody = this._executeRESTCall(rQuestionResponse);

		return responseBody;

		/*
			In the response body that's returned, the  data.result_sets[x].passed node will
			 contain the number of machines which passed both the management rights and the
			 "with" clause for a given question. *Once populated*, that value should be used as
			 the denominator for determining the fraction of clients that have responded to a
			 question.
			If the question response API is called IMMEDIATELY after the question is asked,
			 the data.result_sets[x].passed will be 0. In this case, the "estimated_total"
			 node should be used as the denominator for determining what fraction of clients
			 has responded.
			The numerator for determining this fraction (that is, the number of clients which
			 have responded so far) is stored in the data.result_sets[x].report_count.
			If the value in data.result_sets[x].passed is 10 and data.result_sets[x].report_count
			 is 5, then 50% of clients have responded so far.
		*/
	},

	/**
	 * Automatically update the API token stored in the x_taniu_tan_core.tanium_api_token
	 *  system property, using Basic Auth, if possible.
	 * @return {boolean} - True if successful, false if something went wrong.
	 */
	updateAPIToken: function() {
		var newAPIToken = this._getNewAPITokenWithExistingToken();

		if (!newAPIToken) {
			newAPIToken = this._getNewAPITokenWithSession();
		}

		if (!newAPIToken) {
			gs.error('Unable to update API token. Halting updateAPIToken function.');
			return false;
		}

		gs.setProperty('x_taniu_tan_core.tanium_api_token', newAPIToken);
		this.tanium_api_token = newAPIToken;

		return true;
	},

	/**
	 * Get a list of all RELEVANT installed solutions in the connected Tanium instance (see
	 *  documented return prototype for a list of packages by node name).
	 * If a given solution IS installed, then in addition to the solution's "installed" node
	 *  being set to true, you'll also find nodes for "id", "display_name", and "version".
	 * @returns {{Tanium_Trends: {installed: boolean}, Tanium_Integrity_Monitor: {installed:
	 *     boolean}, Tanium_Enforce: {installed: boolean}, Tanium_API_Gateway: {installed:
	 *     boolean}, Tanium_Core_ADQuery_Content: {installed: boolean}, Tanium_System_User:
	 *     {installed: boolean}, Tanium_Impact: {installed: boolean}, Tanium_Discover: {installed:
	 *     boolean}, Tanium_Interact: {installed: boolean}, Tanium_Client_Management: {installed:
	 *     boolean}, Tanium_Protect: {installed: boolean}, Tanium_Direct_Connect: {installed:
	 *     boolean}, Tanium_Reveal: {installed: boolean}, Tanium_Deploy: {installed: boolean},
	 *     Application_Usage: {installed: boolean}, Tanium_Connect: {installed: boolean},
	 *     Tanium_Performance: {installed: boolean}, Tanium_Threat_Response: {installed: boolean},
	 *     Tanium_Map: {installed: boolean}, Tanium_Comply: {installed: boolean}, Tanium_Asset:
	 *     {installed: boolean}, EnhancedTags: {installed: boolean}, Tanium_Patch: {installed:
	 *     boolean}, Tanium_Platform_Services: {installed: boolean}}}
	 * @example
	 * var tic = new TaniumIntegrationCore();
	 * gs.info(
	 *     JSON.stringify(tic.getInstalledSolutions(), null, 2)
	 * );
	 */
	getInstalledSolutions: function() {
		var serverInfo, installedSolutionsResponse, solutionName, currentSolution;
		var rGetServerInfo = this._getRESTObject(
			'Tanium Integration Core',
			'Get Tanium Server Info'
		);
		var installedSolutions = {
			'Tanium_Interact': {
				'installed': false
			},
			'Tanium_Performance': {
				'installed': false
			},
			'Tanium_Reveal': {
				'installed': false
			},
			'Tanium_Asset': {
				'installed': false
			},
			'Tanium_Patch': {
				'installed': false
			},
			'Tanium_Protect': {
				'installed': false
			},
			'Tanium_Trends': {
				'installed': false
			},
			'Tanium_Connect': {
				'installed': false
			},
			'Tanium_Impact': {
				'installed': false
			},
			'Tanium_Map': {
				'installed': false
			},
			'Tanium_Comply': {
				'installed': false
			},
			'Tanium_Deploy': {
				'installed': false
			},
			'Tanium_Discover': {
				'installed': false
			},
			'Tanium_Enforce': {
				'installed': false
			},
			'Tanium_Integrity_Monitor': {
				'installed': false
			},
			'Tanium_Threat_Response': {
				'installed': false
			},
			'Tanium_API_Gateway': {
				'installed': false
			},
			'Tanium_Direct_Connect': {
				'installed': false
			},
			'Application_Usage': {
				'installed': false
			},
			'EnhancedTags': {
				'installed': false
			},
			'Tanium_Client_Management': {
				'installed': false
			},
			'Tanium_Core_ADQuery_Content': {
				'installed': false
			},
			'Tanium_System_User': {
				'installed': false
			},
			'Tanium_Platform_Services': {
				'installed': false
			}
		};

		rGetServerInfo.setStringParameterNoEscape(
			'tanium_api_endpoint',
			this.TANIUM_API_ENDPOINT
		);
		try {
			serverInfo = this._executeRESTCall(rGetServerInfo);
		} catch (ex) {
			gs.debug(
				'Unable to get installed solutions from the configured Tanium server. This ' +
				'may indicate that the Tanium service account or API token configured in ' +
				'the Tanium Integration Core application does not have sufficient ' +
				'permissions to access data about installed solutions using the ' +
				'/api/v2/solutions API endpoint. \n' +
				'Please ensure that the service account configured for Tanium Integration ' +
				'Core has sufficient permissions to access this data.\n\n' +
				'Error message: ' + ex.message
			);
		}
		if (
			!serverInfo.hasOwnProperty('data') ||
			!serverInfo.data.hasOwnProperty('Diagnostics') ||
			!serverInfo.data.Diagnostics.hasOwnProperty('Installed_Solutions')
		) {
			throw new Error(
				'Unable to retrieve installed solutions from Tanium Server. Response body:\n' +
				JSON.stringify(serverInfo, null, 2)
			);
		}

		installedSolutionsResponse = serverInfo.data.Diagnostics.Installed_Solutions;

		for (solutionName in installedSolutionsResponse) {
			currentSolution = installedSolutionsResponse[solutionName];
			//If the version node is not blank, then the solution is installed.
			if (currentSolution.version && installedSolutions.hasOwnProperty(solutionName)) {
				installedSolutions[solutionName].installed = true;
				installedSolutions[solutionName].id = currentSolution.id.toString();
				installedSolutions[solutionName].display_name = currentSolution.name.toString();
				installedSolutions[solutionName].version = currentSolution.version.toString();
			}
		}

		return installedSolutions;
	},

	/**
	 * Get a list of all running processes from the specified endpoint, including process ID,
	 *  process name (file name, including extension), CPU use and kernel time, resident
	 *  memory utilization in bytes, and any command-line run information.
	 * @param {String} endpointSerialNumber - An array of objects representing each process
	 *  running on the target machine. An example of one object in the returned array might
	 *  look like this:
	 * {
	 * 	"pid": 2448,
	 * 	"name": "winlogon.exe",
	 * 	"cpuUserTimeSeconds": 0.03125,
	 * 	"cpuKernelTimeSeconds": 0.125,
	 * 	"memoryResidentBytes": 245760,
	 * 	"commandLine": "winlogon.exe"
	 * }
	 * If something goes wrong (such as the machine is offline or the response contains no
	 *  data), a blank array may be returned.
	 * @return {[{cpuKernelTimeSeconds: number, memoryResidentBytes: number, cpuUserTimeSeconds:
	 *     number, name: string, pid: number, commandLine: string}]}
	 */
	getRunningProcesses: function(endpointSerialNumber) {
		var directConnectionResponse;
		var endpointID = this.getEndpointIDBySerial(endpointSerialNumber);
		this.establishDirectConnection(endpointID);
		directConnectionResponse = this.queryOpenDirectConnection(endpointID);

		if (
			!directConnectionResponse.hasOwnProperty('data') ||
			!directConnectionResponse.data.hasOwnProperty('directEndpoint') ||
			!directConnectionResponse.data.directEndpoint.hasOwnProperty('processes') ||
			!directConnectionResponse.data.directEndpoint.processes.hasOwnProperty('all')
		) {
			return [];
		}

		return directConnectionResponse.data.directEndpoint.processes.all;
	},

	/**
	 *
	 * @param {String} endpointSerialNumber - The serial number of the specific endpoint on which
	 *  to get the process ID for the specified process name.
	 * If this is not specified, endpointID must be.
	 * @param {String} processName - The name of the process (including any file extension).
	 * Example: "notepad.exe"
	 * @param {String|Number} [endpointID=this.getEndpointIDBySerial(endpointSerialNumber)] -
	 *  Optionally specify the endpoint ID. If this is not specified, endpointSerialNumber
	 *  must be. If it IS specified, endpointSerialNumber is not used.
	 * @return {String[]}
	 * @example
	 * var i, notepadPID;
	 * var computerSerialNumber = 'some_serial_number';
	 * var tanActionUtil = new x_taniu_tan_core.TaniumActionUtil();
	 * //Method inherited from the extended TaniumIntegrationCore. Also works with Int Core SI.
	 * var endpointID = tanActionUtil.getEndpointIDBySerial(computerSerialNumber);
	 * notepadPID = tanActionUtil.getProcessIDsByName(null, 'notepad.exe', endpointID)[0];
	 * //Optionally, use endpoint serial instead:
	 * //notepadPID = tanActionUtil.getProcessIDsByName(computerSerialNumber, 'notepad.exe');
	 * tanActionUtil.killProcessOnEndpoint(
	 *    null, //Optionally, specify the computer serial number and skip endpointID
	 *    'notepad.exe',
	 *    notepadPID,
	 *    endpointID
	 * );
	 */
	getProcessIDsByName: function(
		endpointSerialNumber,
		processName,
		endpointID
	) {
		var i, directConnectionResponse;
		var processList = [];
		var processIDs = [];
		if (!endpointID) {
			if (!endpointSerialNumber) {
				throw new Error(
					'Error when attempting to kill process on endpoint. Endpoint ID ' +
					'or serial number must be specified.'
				);
			}
			endpointID = this.getEndpointIDBySerial(endpointSerialNumber);
		}
		this.establishDirectConnection(endpointID);
		directConnectionResponse = this.queryOpenDirectConnection(endpointID);

		if (
			!directConnectionResponse.hasOwnProperty('data') ||
			!directConnectionResponse.data.hasOwnProperty('directEndpoint') ||
			!directConnectionResponse.data.directEndpoint.hasOwnProperty('processes') ||
			!directConnectionResponse.data.directEndpoint.processes.hasOwnProperty('all')
		) {
			return processIDs;
		}

		processList = directConnectionResponse.data.directEndpoint.processes.all;
		for (i = 0; i < processList.length; i++) {
			if (processList[i].name == processName) {
				processIDs.push(processList[i].pid);
			}
		}

		return processIDs;
	},

	/**
	 * Generate and return a link to the specified question in your Tanium environment.
	 * Not guaranteed to work with TaaS/Tanium Cloud in this version.
	 * @param {Number|String} [questionID=this.question_id] - The numerical question ID from
	 *  Tanium, typically generated by calling .askQuestion() and passing in a question as a
	 *  string.
	 * @return {string}
	 */
	getQuestionLink: function(questionID) {
		var taniumEndpoint = this.TANIUM_API_ENDPOINT;
		questionID = (typeof questionID == 'undefined') ? this.question_id : questionID;
		if (!questionID) {
			throw new Error(
				'.getQuestionLink() called before question_id was set. Please call ' +
				'.askQuestion() first, or specify an existing question ID.'
			);
		}

		taniumEndpoint = taniumEndpoint.substring(0, taniumEndpoint.indexOf('/api'));
		taniumEndpoint += '/#/interact/q/' + this.question_id;

		return taniumEndpoint;
	},

	/**
	 * Establish a direct connection to the specified endpoint.
	 * @param {number|string} endpointID - The ENDPOINT ID (NOT the same as the Computer ID) of an
	 *  endpoint.
	 * @returns {string|boolean} - The direct connection ID. Not actually necessary, as
	 *  .queryOpenDirectConnection() accepts an endpoint ID, not a DC ID.
	 */
	establishDirectConnection: function(endpointID) {
		var responseBody;
		var trackDECActions = (gs.getProperty(
			'x_taniu_tan_core.track_direct_connect_actions',
			'false'
		) === 'true');
		var rEstablishDirectConnection = this._getRESTObject(
			'Tanium Integration Core',
			'Gateway-Establish Direct Connection'
		);

		rEstablishDirectConnection.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);
		rEstablishDirectConnection.setStringParameterNoEscape(
			'endpoint_id',
			endpointID
		);

		//Set HTTP timeout to 2 minutes (120k ms)
		rEstablishDirectConnection.setHttpTimeout(120000);
		/*
			NOTE: The glide.http.outbound.max_timeout.enabled system property controls whether
			 there is a maximum timeout for REST messages.
			If this is set to true (which it almost certainly is), then the
			 glide.http.outbound.max_timeout property controls the length of this maximum timeout.
			Unfortunately, the latter system property's maximum value is 30 (seconds).
			The above API call is not able to override this.
			I've learned that this is because the glide.http.outbound.max_timeout system property
			 controls max timeouts, and has a maximum value of 30 (seconds).
			According to my research and ServiceNow KB0744311, one solution is to set the
			 glide.http.outbound.max_timeout.enabled system property to false, but this would
			 disable the max timeout for ALL REST (and SOAP) calls, instance-wide.
			If you're experiencing this issue, you can try disabling the max_timeout.enabled
			 system property (which is in the global scope). However, this is not officially
			 supported by Tanium, as it is a limitation of the ServiceNow platform.
		 */

		//Second arg to true to prevent hard throw. This will trigger the error message below.
		responseBody = this._executeRESTCall(rEstablishDirectConnection, true);

		if (
			!responseBody.hasOwnProperty('data') ||
			!responseBody.data ||
			!responseBody.data.hasOwnProperty('openDirectConnection') ||
			!responseBody.data.openDirectConnection ||
			!responseBody.data.openDirectConnection.hasOwnProperty('connectionID') ||
			!responseBody.data.openDirectConnection.connectionID
		) {
			gs.error(
				'establishDirectConnection method received invalid response body: \n' +
				JSON.stringify(responseBody, null, 2) + '\nHalting execution.'
			);
			return false; //Halt if error
		}

		//Set scope variable endpoint_id now that a direct connection was established.
		this.endpoint_id = endpointID;
		this.direct_connection_id = responseBody.data.openDirectConnection.connectionID || false;

		if (trackDECActions) {
			this._logAction(
				(this.endpoint_serial_number || ''),
				this.endpoint_id,
				'Direct Connect - Open Session',
				'Establish Direct Connection to endpoint with Tanium Endpoint ID ' + this.endpoint_id,
				this.direct_connection_id
			);
		}

		return this.direct_connection_id.toString();
	},

	/**
	 * @param {number|string} [endpointID=this.endpoint_id] - The endpoint ID to query the direct
	 *  connection for.
	 * If unspecified, this method will automatically use the endpoint that was used to establish
	 *  the last direct connection.
	 * This method will only work if a direct connection has recently been established with the
	 *  provided endpoint.
	 * @returns {{cpu_usage_percent : number, ram_usage_percent : number}|boolean}
	 * @example
	 * var cpuAndRamUtilization;
	 * var computerSerialNumber = 'some_serial_number';
	 * var taniumUtil = x_taniu_tan_core.TaniumIntegrationCore();
	 * var endpointID = taniumUtil.getEndpointIDBySerial(computerSerialNumber);
	 * taniumUtil.establishDirectConnection(endpointID);
	 * cpuAndRamUtilization = taniumUtil._queryOpenDirectConnection();
	 * //cpuAndRamUtilization at:
	 * //{
	 * // "cpu_usage_percent": 6,
	 * // "ram_usage_percent": 51
	 * //}
	 */
	queryOpenDirectConnection: function(endpointID) {
		var responseBody;
		/*var cpuRamStats = {
			cpu_usage_percent : -1,
			ram_usage_percent : -1
		};*/

		endpointID = (typeof endpointID == 'undefined') ? this.endpoint_id : endpointID;

		if (!endpointID) {
			throw new Error(
				'.queryOpenDirectConnection() called before endpoint_id or direct_connection_id ' +
				'was set. Please call .establishDirectConnection() first, passing in the endpoint ' +
				'ID. You can get the endpoint ID by calling .getEndpointIDBySerial().'
			);
		}

		var rQueryDirectConnection = this._getRESTObject(
			'Tanium Integration Core',
			'Gateway-Query Direct Connection'
		);

		rQueryDirectConnection.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);
		rQueryDirectConnection.setStringParameterNoEscape(
			'endpoint_id',
			endpointID
		);
		rQueryDirectConnection.setHttpTimeout(120000);

		responseBody = this._executeRESTCall(rQueryDirectConnection, true);

		if (
			!responseBody.hasOwnProperty('data') ||
			!responseBody.data.hasOwnProperty('directEndpoint')
		) {
			gs.error(
				'_queryOpenDirectConnection method received invalid response body: \n' +
				JSON.stringify(responseBody, null, 2) + '\nHalting execution.'
			);
			return false; //Halt if error
		}

		return responseBody;
	},

	/**
	 * Attempts to identify and return the Tanium "Endpoint ID" for the endpoint to which the GlideRecord that's passed into this method is positioned.
	 *
	 * The behavior of this method is determined by the value of the "Identify Endpoint by Field" [x_taniu_tan_core.identify_endpoint_by_field] System Property, documented in the System Properties > Identify Endpoint by Field section of the Tanium Integration Core documentation on the application's page on the ServiceNow store:
	 *
	 * https://store.servicenow.com/sn_appstore_store.do#!/store/application/c4134c50db6ec910495d70f339961931/
	 *
	 * If the endpoint is not found in Tanium, this method will log a warning and return false.
	 * If more than one endpoint is found with the specified match logic, then this method will log a warning and return the first ID it finds or, if falseWhenMultipleFound is set to true, it will log an error and return false instead.
	 *
	 * @param {GlideRecord} grEndpoint - A GlideRecord object positioned to the endpoint for which to get the Tanium Endpoint ID.
	 *
	 * @param {"serial"|"fqdn"|"fqdn_and_serial"|"fqdn_or_serial"|"serial_or_fqdn"} [overrideMatchBehavior=] - Specify this argument to override the system property value for the endpoint matching behavior, for this one method call.
	 * Must be one of the enumerated values.
	 *
	 * @param {boolean} [falseWhenMultipleFound=false] - If true, this method will log an error and return false if more than one endpoint is found in Tanium matching the provided FQDN and/or serial number using the specified match logic.
	 * If false (or unspecified), it will log a warning but will still return the first Endpoint ID found.
	 * This may be useful for scenarios where you need to be certain that you've uniquely identified a single specific endpoint, and cannot risk a mismatch, duplicate, or false positive.
	 *
	 * @example
	 * var endpointID;
	 * var tic = new TaniumIntegrationCore();
	 * var current = new GlideRecord('cmdb_ci_win_server');
	 *
	 * if (current.get('5c15ca571b9d0210216efeee034bcb21')) {
	 *     endpointID = tic.getEndpointID(current);
	 * 	gs.info('Endpoint ID: ' + endpointID);
	 * }
	 *
	 * @version 2.0.0
	 */
	getEndpointID: function(
		grEndpoint,
		overrideMatchBehavior,
		falseWhenMultipleFound
	) {
		var responseBody, endpointID;
		var matchBehavior = this._getEndpointMatchBehavior(
			grEndpoint,
			overrideMatchBehavior
		);
		if (!matchBehavior) {
			gs.error(
				'Unable to get endpoint ID. Invalid match behavior specified. ' +
				'Halting execution.'
			);
			return false;
		}
		var queryVars = this._getEndpointMatchQueryVariablesObj(
			grEndpoint,
			matchBehavior
		);
		var rGetEndpointID = this._getRESTObject(
			'Tanium Integration Core',
			'Gateway-Get Endpoint ID by FQDN/Serial'
		);

		falseWhenMultipleFound = (typeof falseWhenMultipleFound == 'undefined') ? false : !!falseWhenMultipleFound;

		rGetEndpointID.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);
		rGetEndpointID.setStringParameterNoEscape(
			'query_variables',
			JSON.stringify(queryVars)
		);

		responseBody = this._executeRESTCall(
			rGetEndpointID,
			true
		);

		if (!responseBody) {
			gs.error(
				'.getEndpointID() method received no response body from Tanium. ' +
				'This may be caused by a missing endpoint or invalid query. \n' +
				'Halting execution.'
			);
			return false; //Halt if error
		}

		//Make sure that response has the expected structure.
		if (
			!responseBody.hasOwnProperty('data') ||
			!responseBody.data ||
			!responseBody.data.hasOwnProperty('endpoints') ||
			!responseBody.data.endpoints ||
			!responseBody.data.endpoints.hasOwnProperty('edges') ||
			!responseBody.data.endpoints.edges
		) {
			gs.error(
				'getEndpointID method received invalid response body: \n' +
				JSON.stringify(responseBody, null, 2) + '\nHalting execution.'
			);
			return false; //Halt if error
		}

		if (responseBody.data.endpoints.edges.length < 1) {
			gs.warn(
				'No endpoints found in Tanium matching the provided FQDN ' +
				'and/or serial using match logic ' + matchBehavior + ' for endpoint ' +
				'with sys_id ' + grEndpoint.getValue('sys_id') + '.'
			);
			return false;
		}

		//If more than one endpoint is found, log a warning and return the first one.
		if (responseBody.data.endpoints.edges.length > 1) {
			if (falseWhenMultipleFound) {
				gs.error(
					'More than one endpoint found in Tanium matching the provided FQDN ' +
					'and/or serial using match logic ' + matchBehavior + ' for endpoint ' +
					'with sys_id ' + grEndpoint.getValue('sys_id') + '. ' +
					'Halting execution and returning false since the falseWhenMultipleFound ' +
					'argument is set to true. \n' +
					'Response body: \n' +
					JSON.stringify(responseBody, null, 2)
				);
				//Return false if more than one endpoint is found and falseWhenMultipleFound is true.
				return false;
			} else {
				//Log a warning if more than one endpoint is found and falseWhenMultipleFound is false.
				//Later, we'll return the EID of the first endpoint found.
				gs.warn(
					'More than one endpoint found in Tanium matching the provided FQDN ' +
					'and/or serial using match logic ' + matchBehavior + ' for endpoint ' +
					'with sys_id ' + grEndpoint.getValue('sys_id') + '. ' +
					'Using the first one found. \n' +
					'Response body: \n' +
					JSON.stringify(responseBody, null, 2)
				);
			}
		}

		endpointID = responseBody.data.endpoints.edges[0].node.id;
		return endpointID;
	},

	/**
	 * Not the same as computer ID!
	 * Sets the "this.endpoint_id" property of this SI, which is required for some methods such
	 *  as _queryOpenDirectConnection().
	 * @param {string} computerSerialNumber - The serial number of the computer to get the endpoint
	 *  ID of. Should be found in the CI's "serial_number" field. MUST match the serial number in
	 *  Tanium.
	 * @example
	 * new x_taniu_tan_core.TaniumIntegrationCore().getEndpointIDBySerial(
	 *  'some_serial_number'
	 * );
	 */
	getEndpointIDBySerial: function(computerSerialNumber) {
		var responseBody, responseHasItems;
		var rGetEndpointID = this._getRESTObject(
			'Tanium Integration Core',
			'Gateway-Get Endpoint ID by Serial'
		);

		rGetEndpointID.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);
		rGetEndpointID.setStringParameterNoEscape('computer_serial_number', computerSerialNumber);

		responseBody = this._executeRESTCall(rGetEndpointID);
		responseHasItems = (
			(
				responseBody.hasOwnProperty('data') &&
				responseBody.data
			) &&
			(
				responseBody.data.hasOwnProperty('assets') &&
				responseBody.data.assets
			) &&
			(
				responseBody.data.assets.hasOwnProperty('items') &&
				responseBody.data.assets.items
			) &&
			responseBody.data.assets.items.length >= 1
		);
		//If the response from Tanium does not contain a valid body with a populated
		// data.assets.items node, log an error and return false.
		if (!responseHasItems) {
			gs.error(
				'getEndpointIDBySerial method received invalid response body: \n' +
				JSON.stringify(responseBody, null, 2) + '\n' +
				'This often indicates that no items were returned in the response, indicating ' +
				'that the endpoint is not managed by Tanium.\n' +
				'Halting execution.'
			);
			return false; //Halt if error
		}

		/***ERROR CHECKING DANCE IS NOW OVER, RETURN TO YOUR LIVES ***/

		this.endpoint_serial_number = computerSerialNumber;
		this.endpoint_id = responseBody.data.assets.items[0].id || false;
		return this.endpoint_id;
	},

	getEndpointSerialByID: function(endpointID) {
		var queryUtil, queryResponse, endpointSerial;

		if (!endpointID) {
			throw new Error(
				'Endpoint ID not specified. TaniumIntegrationCore.getEndpointSerialByID() is ' +
				'not able to get the serial number for an endpoint if an endpoint ID is not ' +
				'specified.'
			);
		}

		queryUtil = new GatewayQueryUtil();
		queryUtil.useCachedData();
		queryUtil.setPageSize(1);
		queryUtil.addFilter('id', 'EQ', endpointID);
		queryUtil.addSensor('Computer Serial Number');

		queryResponse = queryUtil.getNextPage();

		//Check that the returned object isn't going to throw a hard error when we try to
		// access the serial number... it's a lot of steps.
		if (
			!queryResponse.hasOwnProperty('data') ||
			!queryResponse.data.hasOwnProperty('endpoints') ||
			!queryResponse.data.endpoints.hasOwnProperty('edges') ||
			!queryResponse.data.endpoints.edges.length >= 1 ||
			!queryResponse.data.endpoints.edges[0].hasOwnProperty('node') ||
			!queryResponse.data.endpoints.edges[0].node.hasOwnProperty('sensorReadings') ||
			!queryResponse.data.endpoints.edges[0].node.sensorReadings.hasOwnProperty('columns') ||
			!queryResponse.data.endpoints.edges[0].node.sensorReadings.columns.length >= 1 ||
			!queryResponse.data.endpoints.edges[0].node.sensorReadings.columns[0].hasOwnProperty('name') ||
			!queryResponse.data.endpoints.edges[0].node.sensorReadings.columns[0].name === 'Computer Serial Number' ||
			!queryResponse.data.endpoints.edges[0].node.sensorReadings.columns[0].hasOwnProperty(
				'values') ||
			!queryResponse.data.endpoints.edges[0].node.sensorReadings.columns[0].values.length >= 1 ||
			!queryResponse.data.endpoints.edges[0].node.sensorReadings.columns[0].values[0]
		) {
			//Return false if the response is invalid, probably meaning the specified endpoint ID is
			// invalid.
			gs.warn(
				'Serial number not found for endpoint with Tanium Endpoint ID ' +
				endpointID + ', which may indicate that the ID is not valid.'
			);
			return false;
		}

		endpointSerial = queryResponse.data.endpoints.edges[0].node.sensorReadings.columns[0].values[0];
		return endpointSerial;
	},

	/**
	 * Create a new Tanium Computer Group (including Filter Group, Management Rights Group, or
	 *  both), and add it to a Content Set (if desired).
	 *
	 * @param {String} groupName - The name of the Tanium Computer Group to create. MUST BE UNIQUE.
	 * @param {String} [queryText=] - The query text to use to determine which endpoints should be
	 *  in the newly created group. For example:
	 * "Computer serial number equals some_serial_number".
	 * This would include the one machine with that serial number in the group, and no others.
	 * @param {Boolean} [isManagementRightsGroup=true] - Optionally, specify whether this group
	 *  should be a "management rights group" in Tanium. If not specified, the default value is
	 *     true. Note that in order to be used for Patch targeting, this must be set to true (or
	 *     not specified; the default being true).
	 * @param {Boolean} [isFilterGroup=true] - Optionally, specify whether this group should be
	 *  able to be used in filters in the Tanium platform. If not specified, the default value is
	 *  true.
	 * @param {String} [contentSetName=] - If you want this group to be a filter group, and be a
	 *  member of anything other than the "Default Filter Group" content set, you can specify the
	 *  Tanium Content Set name here.
	 * If unspecified, groups are added to the Default Filter Groups content set automatically when
	 * isFilterGroup is set to true.
	 *
	 * @return {number} - The ID of the Tanium Computer Group (i.e. 586947).
	 *
	 * @example
	 * var tic = new x_taniu_tan_core.TaniumIntegrationCore();
	 * gs.info(tic.createComputerGroup(
	 *     'Newly created computer group',
	 *     'Computer serial number equals some_serial_number'
	 * )); //Response: 586947 (a Tanium computer group ID)
	 */
	createComputerGroup: function(
		groupName,
		queryText,
		isManagementRightsGroup,
		isFilterGroup,
		contentSetName
	) {
		isManagementRightsGroup = (typeof isManagementRightsGroup == 'undefined') ? true : isManagementRightsGroup;
		isFilterGroup = (typeof isFilterGroup == 'undefined') ? true : isFilterGroup;

		var responseBody, newGroupID;
		var requestBody = {};
		var rCreateComputerGroup = this._getRESTObject(
			'Tanium Integration Core',
			'Groups-Create Computer Group'
		);

		if (!groupName) {
			throw new Error(
				'createComputerGroup() called without group name. Group name is required, and ' +
				'must be unique when creating a new Tanium Computer Group.'
			);
		}

		requestBody.name = groupName;
		requestBody.filter_flag = isFilterGroup;
		requestBody.management_rights_flag = isManagementRightsGroup;

		if (queryText) {
			requestBody.text = queryText;
		}
		if (contentSetName) {
			requestBody.content_set = {
				'name': contentSetName
			};
		}

		rCreateComputerGroup.setStringParameterNoEscape(
			'tanium_api_endpoint',
			this.TANIUM_API_ENDPOINT
		);
		rCreateComputerGroup.setRequestBody(
			JSON.stringify(requestBody)
		);

		responseBody = this._executeRESTCall(rCreateComputerGroup);

		if (
			!responseBody.hasOwnProperty('data') ||
			!responseBody.data.hasOwnProperty('id') ||
			!responseBody.data.id
		) {
			throw new Error(
				'Invalid response body when attempting to create Tanium Computer Group ' +
				groupName + ':\n' +
				JSON.stringify(responseBody, null, 2)
			);
		}

		newGroupID = responseBody.data.id;
		gs.debug('Created new Tanium Computer Group with name "' + groupName + '", and ID "' + newGroupID + '".');

		return newGroupID;
	},

	/**
	 * Retrieve the operating system for the specified endpoint, by Tanium endpoint ID.
	 * useLiveData should default to false
	 * This method is slightly more efficient than .getOperatingSystemFromEndpointBySerial()
	 *  because it doesn't need to look up the endpoint ID before getting the OS.
	 * @param {String|number} endpointID - The Tanium "endpoint ID" for the endpoint from which
	 *  to retrieve the operating system.
	 * @param {Boolean} [useLiveData=false] - Set to true to use live rather than cached
	 *  data when determining the endpoint.
	 * This should almost always be left as false.
	 */
	getOperatingSystemFromEndpointByID: function(endpointID, useLiveData) {
		return this._getOperatingSystemFromEndpoint(endpointID, useLiveData);
	},

	/**
	 * Retrieve the operating system for the specified endpoint, by serial number.
	 * useLiveData should default to false
	 * This method is slightly more efficient than .getOperatingSystemFromEndpointBySerial()
	 *  because it doesn't need to look up the endpoint ID before getting the OS.
	 * @param {String|number} endpointSerial - The serial number for the endpoint from which
	 *  to retrieve the operating system.
	 * @param {Boolean} [useLiveData=false] - Set to true to use live rather than cached
	 *  data when determining the endpoint.
	 * This should almost always be left as false.
	 */
	getOperatingSystemFromEndpointBySerial: function(endpointSerial, useLiveData) {
		var endpointID = this.getEndpointIDBySerial(endpointSerial);
		return this._getOperatingSystemFromEndpoint(endpointID, useLiveData);
	},

	/**
	 * Set whether any REST calls made by this class (or any class which extends it without
	 *  overriding this property or behavior) should be made by the instance asynchronously.
	 * This impacts the behavior of the private ._executeRESTCall() method. Only internal
	 *  code should call that method directly.
	 * If the executeAsync argument is set to true when this method is called, then the
	 *  .executeAsync() method of RESTMessageV2 will be used instead of the .execute()
	 *  method. This can result in significantly more time between call and response, but
	 *  may be preferable if the total number or size of requests/responses is very high,
	 *  which could otherwise bog down instance performance.
	 *
	 * There are three primary use-cases for calling this method with the executeAsync
	 *  argument set to true:
	 *  1. You need to perform a very large number of REST calls in a short period of time,
	 *   and the speed of execution of each individual call is less important than minimizing
	 *   the overall impact on instance performance.
	 *  2. You are debugging in your sub-prod environment and need to be able to view the REST
	 *   request and response bodies in the ecc_queue table, but the execution time of each
	 *   call is not critical (in which case you should be sure to either remove the
	 *   .setRESTAsync() call or set the executeAsync argument to false, before promoting
	 *   to production).
	 *  3. You need your REST request and response bodies to be auditable and visible
	 *   in the ecc_queue table in production (at the cost of additional execution time
	 *   per thread) and either the code is being executed outside an interactive user
	 *   session (such as within a scheduled job or asynchronous Flow), or auditability
	 *   is more important than the user experience resulting from the additional
	 *   execution time.
	 *
	 * NOTE: This does NOT make the JavaScript call itself asynchronous. It only makes the
	 *  REST call asynchronous on a sort of internal level. The JavaScript call will still
	 *  block until the REST call is complete. This is more about how the REST call is
	 *  handled by the ServiceNow instance, not how the JavaScript is handled.
	 *
	 * @param {Boolean} [executeAsync=true] - Whether to execute REST calls asynchronously.
	 * This impacts the behavior of the private ._executeRESTCall() method. Only internal
	 * code should call that method directly.
	 * If set to true, the .executeAsync() method of RESTMessageV2 will be used instead of
	 *  the .execute() method. This can result in SIGNIFICANTLY  longer time between call
	 *  and response, but may be preferable if the total number or size of requests/responses
	 *  is very high, which could otherwise bog down instance performance.
	 * If the .setRESTAsync() method is not called (or the executeAsync argument is not
	 *  specified), then the value of this.rest_async will be used to determine whether the
	 *  request should execute async.
	 *
	 * Note that the executeAsync argument in the .executeRESTCall() method overrides the
	 *  value set by calling .setRESTAsync(). For example, if I call .setRESTAsync(true)
	 *  and then call this method with the executeAsync argument set to false, the request
	 *  will be executed synchronously.
	 * See this link to ServiceNow's API documentation on .executeAsync():
	 *  https://developer.servicenow.com/dev.do#!/reference/api/sandiego/server/sn_ws-namespace/c_RESTMessageV2API#r_RMV2-executeAsync
	 *
	 *  NOTE: This does NOT make the JavaScript call itself asynchronous. It only makes the
	 *   REST call asynchronous on a sort of internal level. The JavaScript call will still
	 *   block until the REST call is complete. This is more about how the REST call is
	 *   handled by the ServiceNow instance, not how the JavaScript is handled.
	 *
	 * @example
	 *  var tic = new x_taniu_tan_core. TaniumIntegrationCore();
	 *  // Execute REST calls asynchronously (generating ecc_queue records):
	 *  tic.setRESTAsync(true);
	 *  tic.askQuestion(someQuestion);
	 *  //...
	 *
	 * @returns {TaniumIntegrationCore}
	 */
	setRESTAsync: function(executeAsync) {
		this.rest_async = (typeof executeAsync === 'undefined') ? true : !!executeAsync;
		return this;
	},

	/**
	 * Get the correct internal value for the matching behavior of the endpoint based on the provided values, and validate that the matching behavior is valid for the provided endpoint.
	 * @param {GlideRecord} grEndpoint - A GlideRecord object positioned to the endpoint to get the ID matching behavior for.
	 * @param {"serial"|"fqdn"|"fqdn_and_serial"|"fqdn_or_serial"|"serial_or_fqdn"} [overrideBehavior=] - Whether to override the system property value for the endpoint matching behavior. Must be one of the enumerated values.
	 * @private
	 */
	_getEndpointMatchBehavior: function(grEndpoint, overrideBehavior) {
		var matchBehavior = false; //Should not be possible to return this but let's init to false anyway.
		var matchBehaviorPropVal = gs.getProperty(
			'x_taniu_tan_core.identify_endpoint_by_field',
			'Serial or FQDN' //Default value
		);
		//List of valid values for the system property and their corresponding match behavior values.
		var matchBehaviorPropMap = {
			"Serial Number": "serial",
			"FQDN": "fqdn",
			"FQDN and Serial": "fqdn_and_serial",
			"FQDN or Serial": "fqdn_or_serial",
			"Serial or FQDN": "serial_or_fqdn"
		};

		if ( //If overrideBehavior is specified, and is valid, use it. Otherwise, use default.
			(typeof overrideBehavior !== 'undefined') &&
			(['serial', 'fqdn', 'fqdn_and_serial', 'fqdn_or_serial', 'serial_or_fqdn'].indexOf(overrideBehavior) > -1)
		) {
			matchBehavior = overrideBehavior;
		} else { //If overrideBehavior is not specified, or is invalid, use the system property.
			if (matchBehaviorPropMap.hasOwnProperty(matchBehaviorPropVal)) {
				matchBehavior = matchBehaviorPropMap[matchBehaviorPropVal];
			} else { //If the system property is set to an invalid value, throw an error.
				throw new Error(
					'Invalid value for x_taniu_tan_core.identify_endpoint_by_field system property. ' +
					'Valid values are "Serial Number", "FQDN", "FQDN and Serial", "FQDN or Serial", ' +
					'and "Serial or FQDN".'
				);
			}
		}

		if ( //record is not valid, or is not on a valid table
			!grEndpoint ||
			!grEndpoint.isValidRecord() ||
			!grEndpoint.isValidField('serial_number') ||
			!grEndpoint.isValidField('fqdn')
		) {
			throw new Error(
				'Invalid GlideRecord object passed to TaniumIntegrationCore class. ' +
				'The grEndpoint argument must be a GlideRecord positioned to a valid record ' +
				'on the cmdb_ci_computer table or one of its children, and must have the ' +
				'"serial_number" and "fqdn" fields available.'
			);
		} else if ( //If the match behavior is to use the serial AND FQDN, and either field is empty, throw an error.
			matchBehavior === 'fqdn_and_serial' &&
			(
				gs.nil(grEndpoint.serial_number) ||
				gs.nil(grEndpoint.fqdn)
			)
		) {
			gs.error(
				'Unable to get endpoint ID. The match behavior is set to "FQDN and Serial", ' +
				'but the GlideRecord object passed to getEndpointID (with sys_id ' +
				grEndpoint.getUniqueValue() + ') has an empty serial number or FQDN field.'
			);
		}

		return matchBehavior;
	},

	/**
	 *
	 * @param {GlideRecord} grEndpoint - A GlideRecord object positioned to the endpoint to get the ID matching behavior for.
	 *
	 * @param {"serial"|"fqdn"|"fqdn_and_serial"|"fqdn_or_serial"|"serial_or_fqdn"} [matchBehavior=] - Whether to override the system property value for the endpoint matching behavior. Must be one of the enumerated values.
	 *
	 * @returns {{filter: {negated: boolean, filters: *[], any: boolean}}}
	 *
	 * @private
	 */
	_getEndpointMatchQueryVariablesObj: function(grEndpoint, matchBehavior) {
		var endpointSerial = grEndpoint.getValue('serial_number');
		var endpointFQDN = grEndpoint.getValue('fqdn');
		var objQueryVars = {
			"filter": {
				"filters": [],
				"any": true,
				"negated": false
			}
		};

		//This should not be possible, but let's cover our backsides anyway.
		if (!matchBehavior) {
			throw new Error(
				'Unable to get endpoint ID. Match behavior could not be identified. This is a bug. ' +
				'Please contact your administrator.'
			);
		}

		//If match behavior uses serial number and serial is set on CI, add serial number filter.
		if (
			['serial', 'fqdn_and_serial', 'fqdn_or_serial', 'serial_or_fqdn']
				.indexOf(matchBehavior) > -1 &&
			endpointSerial
		) {
			objQueryVars.filter.filters.push({
				"path": "serialNumber",
				"op": "EQ",
				"value": endpointSerial,
				"negated": false,
				"any": true
			});
		}

		//If match behavior uses FQDN and FQDN is set on CI, add FQDN filter.
		if (
			['fqdn', 'fqdn_and_serial', 'fqdn_or_serial', 'serial_or_fqdn']
				.indexOf(matchBehavior) > -1 &&
			endpointFQDN
		) {
			objQueryVars.filter.filters.push({
				"path": "name", //Tanium uses "name" for FQDN.
				"op": "EQ",
				"value": endpointFQDN,
				"negated": false,
				"any": true
			});
		}

		//If the match behavior is "fqdn_and_serial", set the "any" property to false.
		if (matchBehavior === 'fqdn_and_serial') {
			objQueryVars.filter.any = false;
		}

		//If no filters were added, something has gone terribly wrong. Throw an error.
		if (objQueryVars.filter.filters.length === 0) {
			throw new Error(
				'Unable to get endpoint ID. The match behavior is set to "' + matchBehavior + '", ' +
				'but the GlideRecord object passed to getEndpointID (with sys_id ' +
				grEndpoint.getUniqueValue() + ') has no value for either serial number or FQDN. ' +
				'Unable to construct a meaningful filter for the query.'
			);
		}

		return objQueryVars;
	},

	/**
	 * @param {String|Number} endpointID
	 * @param {Boolean} [useLiveData=false]
	 * @returns {"Windows"|"Linux"|"Mac"|"AIX"|false} - The string "Windows", "Linux", "Mac", or
	 *  "AIX", indicating the endpoint's operating system. If the OS cannot be found, or is not
	 *  one of those three, then the boolean false is returned.
	 * @private
	 */
	_getOperatingSystemFromEndpoint: function(endpointID, useLiveData) {
		var i, queryResult;
		var gatewayQueryUtil = new x_taniu_tan_core.GatewayQueryUtil();
		useLiveData = (typeof useLiveData == 'undefined') ? false : useLiveData;
		gatewayQueryUtil.addFilter('id', 'EQ', endpointID.toString());

		gatewayQueryUtil.addSensor('Is Windows');
		gatewayQueryUtil.addSensor('Is Linux');
		gatewayQueryUtil.addSensor('Is Mac');
		gatewayQueryUtil.addSensor('Is AIX');

		useLiveData ? gatewayQueryUtil.useLiveData(1) : gatewayQueryUtil.useCachedData();
		gatewayQueryUtil.setPageSize(1);

		queryResult = gatewayQueryUtil.getNextPage();
		queryResult = queryResult.data.endpoints.edges[0].node.sensorReadings.columns;

		for (i = 0; i < queryResult.length; i++) {
			if (queryResult[i].values[i].toLowerCase() === 'true') {
				switch (queryResult[i].name.toLowerCase()) {
					case 'is windows':
						return 'Windows';
					case 'is linux':
						return 'Linux';
					case 'is mac':
						return 'Mac';
					case 'is aix':
						return 'AIX';
					default:
						return false;
				}
			}
		}

	},

	/**
	 *
	 * @param {String} endpointSerial
	 * @param {String|Number} endpointID
	 * @param {String} actionName
	 * @param {String} actionDetails
	 * @param {String|Number} [actionID='']
	 * @param {boolean} [actionResult=] - If specified, this will override the default value of
	 *  the Status field on the Tanium Action History table. If set to true, the Status field
	 *  will be set to "Completed". If set to false, the Status field will be set to "Failed".
	 *  If not specified, the Status field will be set to its default value: "Unknown".
	 * @returns {string|boolean}
	 * @private
	 */
	_logAction: function(
		endpointSerial,
		endpointID,
		actionName,
		actionDetails,
		actionID,
		actionResult
	) {
		if (gs.getProperty('x_taniu_tan_core.Log Tanium Actions', 'true') !== 'true') {
			return false;
		}
		var grActionLog = new GlideRecord('x_taniu_tan_core_tan_action_history');
		grActionLog.initialize();
		grActionLog.setValue('endpoint_serial', endpointSerial || '');
		grActionLog.setValue('endpoint_id', endpointID || '');
		grActionLog.setValue('action_name', actionName);
		grActionLog.setValue('action_details', actionDetails);
		grActionLog.setValue('action_id', actionID);

		if (typeof actionResult === 'boolean') {
			if (actionResult) {
				grActionLog.setValue('action_status', 'completed');
			} else {
				grActionLog.setValue('action_status', 'failed');
			}
		}

		return grActionLog.insert();
	},

	/**
	 * Private function used primarily by the .askQuestion() method of this SI.
	 *
	 * @param {string} questionText
	 * @return {string|boolean}
	 * @private
	 * @example
	 * var tic = new x_taniu_tan_core.TaniumIntegrationCore();
	 * var questionID = tic._sendQuestion('Get computer name from all machines');
	 */
	_sendQuestion: function(questionText) {
		var responseBody, questionObj, questionID;
		var rAskQuestion = this._getRESTObject('Tanium Integration Core', 'Ask Question');

		questionObj = {'query_text': questionText};

		rAskQuestion.setStringParameterNoEscape(
			'tanium_api_endpoint',
			this.TANIUM_API_ENDPOINT
		);
		rAskQuestion.setStringParameterNoEscape(
			'question_json',
			JSON.stringify(questionObj)
		);

		responseBody = this._executeRESTCall(rAskQuestion);

		//Validate that this property exists and holds a value.
		if (
			!responseBody.hasOwnProperty('data') ||
			!responseBody.data.hasOwnProperty('id') ||
			!responseBody.data.id
		) {
			throw new Error(
				'Question with text "' + questionText + '" sent to Tanium, but ' +
				'invalid response was received: \n' +
				JSON.stringify(responseBody, null, 2)
			);
		}

		questionID = responseBody.data.id.toString();

		return questionID;
	},

	/**
	 * Automatically handles setting MID server on REST Messages if MID server system property
	 *  is set. After using this method to retrieve an initialized REST object, you'll need to
	 *  set any string parameters except for "session_id" (unless addSessionID argument is set
	 *  to false).
	 * @param {String} messageName - The REST <strong>Message</strong> name (probably "Tanium
	 *  Integration Core")
	 *  WITHOUT the scope prefix.
	 * @param {string} methodName - The REST <strong>method</strong> name (such as "Ask Question"
	 *  for example). The REST Method can be found in the REST Message record, in the Methods
	 *  related list.
	 * @param {Boolean} [addSessionID=true] - If set to true (or not specified), the string
	 *  parameter "session_id" will be set to the current session ID. If set to false, that
	 *  parameter will not be specified.
	 * NOTE: This requires that the REST Message you're using have a string parameter with
	 *  the name "session_id" that populates the value for an HTTP header called "session".
	 * @param {Boolean} [skipEccSensor=!!this.TANIUM_MID_SERVER] - Skip the ECC sensor. This
	 *  should typically be used whenever communicating through a MID server, to avoid processing
	 *  delays that may result in an intermittent error. If the MID server system property is set
	 *  (and we are thus using a MID server for this message), then this parameter will be set to
	 *  true by default (or false by default if we aren't using a MID server).
	 *  You can override this behavior by specifying this argument when calling this method, but
	 *  that is not recommended.
	 * @param {Boolean} [addScopePrefix=true] - If true or unspecified, adds the Tanium
	 *  Integration Core scope prefix to the provided REST Message name. Set this to false, to
	 *  construct a REST object using a REST Message/Method that's outside the Tanium
	 *  Integration Core scope.
	 * @return {sn_ws.RESTMessageV2} - The initialized RESTMessageV2 object with the MID server
	 *  properly set, if the MID server system property is set.
	 * @private
	 */
	_getRESTObject: function(messageName, methodName, addSessionID, skipEccSensor, addScopePrefix) {
		addSessionID = (typeof addSessionID == 'undefined') ? true : addSessionID;
		addScopePrefix = (typeof addScopePrefix == 'undefined') ? true : addScopePrefix;
		skipEccSensor = (typeof skipEccSensor == 'undefined') ? (!!this.TANIUM_MID_SERVER) : skipEccSensor;

		if (addScopePrefix) {
			messageName = this.SCOPE_PREFIX + '.' + messageName;
		}

		var rMessage = new sn_ws.RESTMessageV2(messageName, methodName);

		if (this.TANIUM_MID_SERVER) {
			rMessage.setMIDServer(this.TANIUM_MID_SERVER);
		}

		if (skipEccSensor) {
			rMessage.setEccParameter('skip_sensor', true);
		}

		if (addSessionID) {
			rMessage.setStringParameterNoEscape('session_id', this.session_id);
		}

		return rMessage;
	},

	/**
	 *
	 * @param {sn_ws.RESTMessageV2} rMessage - The RESTMessageV2 object to execute, AFTER the
	 *     object has been initialized, configured, and all string parameters have been set.
	 * @param {boolean} [returnFalseOnFailure=false] - If set to true, method will return false
	 *  instead of "throwing" an error when there is a hard failure, such as an unparseable JSON
	 *  object or failed .execute() call.
	 * If set to false (or unspecified), error will be "thrown" and execution will halt.
	 * @param {boolean} [parseJSON=true] - If set to true (or unspecified), JSON will be parsed
	 *  and a JSON object will be returned. Otherwise, the response body will be returned as
	 *  plain text.
	 * @param {boolean} [ignoreHTTPErrors=false] - If set to true, will ignore issues where the
	 *  HTTP status is not success (2xx).
	 * @param {boolean} [executeAsync=false] - If set to true, the .executeAsync() method of
	 *  RESTMessageV2 will be used instead of the .execute() method. This can result in
	 *  SIGNIFICANTLY  longer time between call and response, but may be preferable if the total
	 *  number or size of requests/responses is very high, which could otherwise bog down
	 *  instance performance.
	 * If this argument is not specified, then the value of this.rest_async will be used to
	 *  determine whether the request should execute async. The default value of that property
	 *  is false.
	 * In addition to specifying the executeAsync argument when calling this method, one may also
	 *  call the .setRESTAsync() method and pass in the boolean true to set this behavior.
	 * Note that the executeAsync argument in this method overrides the value set by calling
	 *  .setRESTAsync(). For example, if I call .setRESTAsync(true) and then call this method with
	 *  the executeAsync argument set to false, the request will be executed synchronously.
	 * See this link to ServiceNow's API documentation on .executeAsync():
	 * https://developer.servicenow.com/dev.do#!/reference/api/sandiego/server/sn_ws-namespace/c_RESTMessageV2API#r_RMV2-executeAsync
	 * @return {Object|Boolean} - A JSON object containing the response body
	 * @private
	 */
	_executeRESTCall: function(
		rMessage,
		returnFalseOnFailure,
		parseJSON,
		ignoreHTTPErrors,
		executeAsync
	) {
		var responseObj, responseBody, httpStatus;

		//Set default values
		returnFalseOnFailure = (typeof returnFalseOnFailure == 'undefined') ? false : returnFalseOnFailure;
		parseJSON = (typeof parseJSON == 'undefined') ? true : parseJSON;
		ignoreHTTPErrors = (typeof ignoreHTTPErrors == 'undefined') ? false : ignoreHTTPErrors;
		executeAsync = (typeof executeAsync == 'undefined') ? this.rest_async : executeAsync;

		if (executeAsync) {
			rMessage.setEccParameter('skip_sensor', true);
		}

		try {
			//Execute REST message
			//responseObj = rMessage.execute();
			responseObj = (executeAsync) ? (rMessage.executeAsync()) : (rMessage.execute());
			httpStatus = responseObj.getStatusCode();
			responseBody = responseObj.getBody();
			if ((!ignoreHTTPErrors) && (httpStatus.toString().indexOf('2') !== 0)) {
				//If status code not 2xx, throw an error and halt, or return false
				throw new Error('API call failed with non-"2xx" status code ' + httpStatus);
			}
			responseBody = (parseJSON) ? (JSON.parse(responseBody)) : (responseObj);
		} catch (err) {
			gs.error(
				'Error running Tanium API call. \n' +
				'Error message: ' + err.message// + '\nResponse body: \n' + responseBody.toString()
			);
			if (returnFalseOnFailure) {
				return false;
			} else {
				throw err;
			}
		}

		return responseBody;
	},

	/**
	 * This will transform a question response returned from the platform API
	 *  (TaniumIntegrationCore.getQuestionResponse()) - it is not to be used for responses
	 *  from the API Gateway query APIs.
	 * @param {Object} platformResponse
	 * @returns {{columns: String[], rows: [String[]]}}
	 * @private
	 */
	_transformPlatformQuestionResponse: function(platformResponse) {
		var iColumn, columnName, iRow, responseColumns, responseRows;
		var transformedData = {
			'columns': [],
			'rows': []
		};

		//Check for incomplete response
		if (
			!platformResponse.hasOwnProperty('data') ||
			!platformResponse.data.hasOwnProperty('result_sets') ||
			!platformResponse.data.result_sets.length > 0 ||
			!platformResponse.data.result_sets[0].hasOwnProperty('columns') ||
			!platformResponse.data.result_sets[0].columns.length > 0 ||
			!platformResponse.data.result_sets[0].hasOwnProperty('rows') ||
			!platformResponse.data.result_sets[0].rows.length > 0
		) {
			return transformedData;
		}

		responseColumns = platformResponse.data.result_sets[0].columns;
		responseRows = platformResponse.data.result_sets[0].rows;

		//Populate the list of responseColumns into the returnable object
		for (iColumn = 0; iColumn < responseColumns.length; iColumn++) {
			columnName = responseColumns[iColumn].name;

			transformedData.columns.push(columnName);
		}
		for (iRow = 0; iRow < responseRows.length; iRow++) {
			transformedData.rows.push({});
			for (iColumn = 0; iColumn < transformedData.columns.length; iColumn++) {
				columnName = transformedData.columns[iColumn];

				transformedData.rows[iRow][columnName] = responseRows[iRow].data[iColumn][0].text;
			}
			//responseRows[iRow].data[iColumn][0].text
		}

		return transformedData;
	},

	/**
	 * @return {{valid: boolean, error: string}}
	 * @private
	 */
	_validateEnvironment: function() {
		var returnObject = {
			'valid': true,
			'error': ''
		};
		//Validate endpoint is set and begins with https
		if (
			!this.TANIUM_API_ENDPOINT ||
			this.TANIUM_API_ENDPOINT.indexOf('https') !== 0
		) {
			returnObject.valid = false;
			returnObject.error = 'Missing or malformed system property ' +
				'"x_taniu_tan_core.tanium_api_endpoint". Property must be set, and must begin ' +
				'with https.';

			return returnObject;
		}

		/*if (
			!this.TANIUM_MODULE_API_ENDPOINT ||
			this.TANIUM_MODULE_API_ENDPOINT.indexOf('https') != 0
		) {
			return {
				'valid' : false,
				'error' : 'Missing or malformed system property "x_taniu_tan_core.tanium_module_api_url". Property must be set, and must begin with https.'
			};
		}*/

		//If (username AND password are missing) AND Tanium API token is missing, throw an error.
		//If username and password are missing but token is provided, do not throw an error.
		if ((!this.tanium_username || !this.tanium_password) && !this.tanium_api_token) {
			if (!this.tanium_username) {
				returnObject.valid = false;
				returnObject.error = 'Missing or malformed system property ' +
					'"x_taniu_tan_core.tanium_username". Either username and password, or API token properties must be set.';

				//return returnObject;
			}

			if (!this.tanium_password) {
				returnObject.valid = false;
				returnObject.error = 'Missing or malformed system property ' +
					'"x_taniu_tan_core.tanium_password". Either username and password, or API token properties must be set.';

				//return returnObject;
			}

			if (!this.tanium_api_token) {
				returnObject.valid = false;
				returnObject.error = 'Missing or malformed system property ' +
					'"x_taniu_tan_core.tanium_password". Either username and password, or API token properties must be set.';
			}
		}

		return returnObject;
	},

	/**
	 * @return {*}
	 * @private
	 */
	_loginGetSessionID: function() {
		var responseBody, sessionID;
		var rLogin = this._getRESTObject(
			'Tanium Integration Core',
			'Login - Get Session ID',
			false
		);

		rLogin.setStringParameterNoEscape(
			'username',
			this.tanium_username
		);
		rLogin.setStringParameterNoEscape(
			'password',
			this.tanium_password
		);
		rLogin.setStringParameterNoEscape(
			'tanium_api_endpoint',
			this.TANIUM_API_ENDPOINT
		);

		responseBody = this._executeRESTCall(rLogin);
		sessionID = responseBody.data.session.toString();

		if (!sessionID) {
			throw new Error(
				'Unable to log in to Tanium using service account username ' +
				this.tanium_username + ' and API endpoint ' + this.TANIUM_API_ENDPOINT + '.'
			);
		}

		return sessionID;
	},

	/**
	 * Rotate the API Token if it exists, and return the new token.
	 * @return {String|boolean} - The new API token if successful, or boolean false if not.
	 * @private
	 */
	_getNewAPITokenWithExistingToken: function() {
		var rGetNewTokenWithToken, responseBody;
		var apiToken = this.tanium_api_token || '';

		if (!apiToken) {
			return false;
		}

		rGetNewTokenWithToken = this._getRESTObject(
			'Tanium Integration Core',
			'Get new API Token (with existing token)'
		);

		rGetNewTokenWithToken.setStringParameterNoEscape(
			'tanium_api_endpoint',
			this.TANIUM_API_ENDPOINT
		);
		rGetNewTokenWithToken.setStringParameterNoEscape(
			'api_token',
			apiToken
		);

		responseBody = this._executeRESTCall(rGetNewTokenWithToken);

		if (
			!responseBody.hasOwnProperty('data') ||
			!responseBody.data ||
			!responseBody.data.hasOwnProperty('token_string') ||
			!responseBody.data.token_string
		) {
			//Something has gone wrong. Sound the alarm. Wee-woo, wee-woo.
			gs.error(
				'Error retrieving new API token from Tanium using existing API token.\n' +
				'Using endpoint: ' + this.TANIUM_API_ENDPOINT + '\n' +
				'Response: \n' + JSON.stringify(responseBody)

				//Response logging redacted to avoid accidentally logging a sensitive API token
			);

			return false;
		}

		//Return new token string
		return responseBody.data.token_string;
	},

